-- PostgreSQL: create the Swiss namespace hierarchy
CREATE DATABASE alpineenergy_ch;
\connect alpineenergy_ch
CREATE SCHEMA bronze;
CREATE SCHEMA silver;
CREATE SCHEMA gold;

-- Spark SQL: mirror the namespace hierarchy
CREATE DATABASE alpine_ch;
CREATE TABLE alpine_ch.silver.meter_readings (
    meter_id       STRING,
    daily_kw       DOUBLE,
    date           DATE,
    region         STRING,
    customer_type  STRING
) USING DELTA
PARTITIONED BY (date)
LOCATION 'abfss://datalake@storage.dfs.core.windows.net/alpine_ch/silver/meter_readings';

-- The naming convention makes cross-engine mapping trivial:
-- PostgreSQL:  alpineenergy_ch.silver.meter_readings
-- Spark SQL:   alpine_ch.silver.meter_readings
-- Same logical table, same hierarchy, different engine prefix

-- PostgreSQL: implement ownership with role-based access
-- Producer team has full access; consumers have SELECT only

-- Create team roles
CREATE ROLE swiss_billing;
CREATE ROLE austrian_analytics;
CREATE ROLE italian_de;
CREATE ROLE platform_team;

-- Grant ownership: swiss_billing owns the billing tables
GRANT ALL ON ALL TABLES IN SCHEMA gold TO swiss_billing;
ALTER DEFAULT PRIVILEGES IN SCHEMA gold
  GRANT SELECT ON TABLES TO austrian_analytics, italian_de;

-- Consumers can read but not write
GRANT USAGE ON SCHEMA gold TO austrian_analytics;
GRANT SELECT ON gold.billing_summary TO austrian_analytics;
GRANT SELECT ON gold.regional_consumption TO austrian_analytics;

-- Revoke write access explicitly to prevent accidents
REVOKE INSERT, UPDATE, DELETE ON gold.billing_summary FROM austrian_analytics;

-- Check the current GEQO threshold and configuration
SHOW geqo_threshold;        -- Default: 12 (tables in FROM clause)
SHOW geqo_effort;           -- Default: 5 (1-10, controls search thoroughness)
SHOW geqo_generations;      -- Default: 0 (auto-calculated from effort)
SHOW geqo_pool_size;        -- Default: 0 (auto-calculated from effort)

-- Force dynamic programming for a complex query (override GEQO)
SET geqo = off;
EXPLAIN (ANALYZE, BUFFERS)
SELECT ... FROM 15_table_join ...;
-- Compare the DP plan vs the GEQO plan
SET geqo = on;
EXPLAIN (ANALYZE, BUFFERS)
SELECT ... FROM 15_table_join ...;

-- PL/pgSQL function that creates next month's partitions
-- Called by Airflow on the 25th of each month
CREATE OR REPLACE FUNCTION platform.create_monthly_partitions(
    target_month DATE
) RETURNS VOID AS $$
DECLARE
    start_date  DATE := DATE_TRUNC('month', target_month);
    end_date    DATE := start_date + INTERVAL '1 month';
    month_suffix TEXT := TO_CHAR(start_date, 'YYYY_MM');
    country     TEXT;
BEGIN
    -- Create the range partition for the month
    EXECUTE format(
        'CREATE TABLE IF NOT EXISTS silver.mr_%s
         PARTITION OF silver.meter_readings_v2
         FOR VALUES FROM (%L) TO (%L)
         PARTITION BY LIST (country)',
        month_suffix, start_date, end_date
    );

    -- Create country sub-partitions
    FOR country IN SELECT unnest(ARRAY['CH', 'AT', 'IT']) LOOP
        EXECUTE format(
            'CREATE TABLE IF NOT EXISTS silver.mr_%s_%s
             PARTITION OF silver.mr_%s FOR VALUES IN (%L)',
            month_suffix, LOWER(country), month_suffix, country
        );
    END LOOP;

    RAISE NOTICE 'Created partitions for %', month_suffix;
END;
$$ LANGUAGE plpgsql;

-- Drop partitions older than the retention period (3 years)
-- Called by Airflow on the 1st of each month
CREATE OR REPLACE FUNCTION platform.enforce_retention(
    retention_months INTEGER DEFAULT 36
) RETURNS VOID AS $$
DECLARE
    cutoff DATE := DATE_TRUNC('month', CURRENT_DATE) - (retention_months || ' months')::INTERVAL;
    rec    RECORD;
BEGIN
    FOR rec IN
        SELECT inhrelid::regclass AS partition_name
        FROM   pg_inherits
          JOIN pg_class ON inhrelid = oid
        WHERE  inhparent = 'silver.meter_readings_v2'::regclass
          AND  pg_get_expr(relpartbound, oid) LIKE '%' || cutoff || '%'
    LOOP
        EXECUTE format('DROP TABLE IF EXISTS %s', rec.partition_name);
        RAISE NOTICE 'Dropped expired partition: %', rec.partition_name;
    END LOOP;
END;
$$ LANGUAGE plpgsql;

-- When a query returns unexpected zero rows, check if RLS is the cause
-- Step 1: Check if RLS is enabled on the table
SELECT relname, relrowsecurity, relforcerowsecurity
FROM   pg_class
WHERE  relname = 'meter_readings' AND relnamespace = 'silver'::regnamespace;

-- Step 2: View the active policies
SELECT polname, polcmd, polroles, pg_get_expr(polqual, polrelid) AS using_expr
FROM   pg_policy
WHERE  polrelid = 'silver.meter_readings'::regclass;

-- Step 3: Test what the current role sees
SET ROLE swiss_analytics;
SELECT COUNT(*) FROM silver.meter_readings WHERE date = '2025-01-15';
-- If 0 rows: the RLS policy is filtering everything for this role
RESET ROLE;

-- Install and configure pgaudit
CREATE EXTENSION pgaudit;

-- Configure audit logging scope
-- Log all SELECT on tables containing PII (via role-based auditing)
ALTER ROLE austrian_analytics SET pgaudit.log = 'read';
ALTER ROLE swiss_billing SET pgaudit.log = 'read, write';

-- Object-level auditing: audit all access to the meter_details table
ALTER TABLE silver.meter_details SET (pgaudit.log = 'all');

-- The audit log appears in PostgreSQL's standard log output:
-- AUDIT: SESSION,1,1,READ,SELECT,TABLE,silver.meter_details,
--   "SELECT meter_id, address FROM silver.meter_details WHERE region = 'BERN-NORTH'",
--   austrian_analytics

